import 'package:flutter_fractals/features/renderer/deep_zoom_precision_policy.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('DeepZoomPrecisionPolicy', () {
    const policy = DeepZoomPrecisionPolicy();

    test('scales GPU iterations for normal zoom levels', () {
      expect(policy.scaledGpuIterations(baseIterations: 100, zoom: 1), 100);
      expect(policy.scaledGpuIterations(baseIterations: 100, zoom: 100), 170);
      expect(
        policy.scaledGpuIterations(baseIterations: 3000, zoom: 1e30),
        DeepZoomPrecisionPolicy.gpuMaxIterations,
      );
    });

    test('handles invalid zoom values without throwing', () {
      expect(
        policy.scaledGpuIterations(baseIterations: 100, zoom: double.nan),
        100,
      );
      expect(
        policy.scaledGpuIterations(baseIterations: 100, zoom: double.infinity),
        DeepZoomPrecisionPolicy.gpuMaxIterations,
      );
      expect(
        policy.scaledGpuIterations(
          baseIterations: 100,
          zoom: double.negativeInfinity,
        ),
        100,
      );
    });

    test('uses explicit precision thresholds at boundary values', () {
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 5e6),
        isTrue,
      );
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 1e12),
        isFalse,
      );
      expect(
        policy.shouldUseCpuFallback(moduleId: 'mandelbrot', zoom: 1e12),
        isTrue,
      );
    });
  });

  group('DeepZoomHysteresis', () {
    test('requires consecutive over-threshold samples for same module', () {
      final hysteresis = DeepZoomHysteresis();

      expect(hysteresis.update(moduleId: 'julia', zoom: 1e9), isFalse);
      expect(hysteresis.update(moduleId: 'julia', zoom: 1e9), isTrue);
      expect(hysteresis.update(moduleId: 'phoenix', zoom: 1e9), isFalse);
      expect(hysteresis.update(moduleId: 'phoenix', zoom: 1e9), isTrue);
      expect(hysteresis.update(moduleId: 'phoenix', zoom: 1), isFalse);
    });
  });
}

